package com.example.app.network;

import okhttp3.CertificatePinner;

public final class CertificatePinningConfig {

    private CertificatePinningConfig() {
        // Prevent instantiation
    }

    /**
     * Creates a CertificatePinner for production API hosts.
     * Pins include both the leaf certificate and a backup pin.
     *
     * To obtain the SHA-256 pin for your server certificate, run:
     *   openssl s_client -servername api.example.com -connect api.example.com:443 | \
     *   openssl x509 -pubkey -noout | \
     *   openssl pkey -pubin -outform der | \
     *   openssl dgst -sha256 -binary | openssl enc -base64
     *
     * Replace the placeholder hashes below with your actual pins before release.
     */
    public static CertificatePinner createProductionPinner() {
        return new CertificatePinner.Builder()
                // Primary pin (leaf/intermediate certificate public key)
                .add("api.example.com",
                        "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=")
                // Backup pin (backup CA or next rotation certificate)
                .add("api.example.com",
                        "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=")
                .build();
    }
}

