package com.example.app.network;

import java.util.concurrent.TimeUnit;

import okhttp3.OkHttpClient;
import okhttp3.logging.HttpLoggingInterceptor;

public final class OkHttpClientFactory {

    private static final int CONNECT_TIMEOUT_SECONDS = 30;
    private static final int READ_TIMEOUT_SECONDS = 30;
    private static final int WRITE_TIMEOUT_SECONDS = 30;

    private OkHttpClientFactory() {
        // Prevent instantiation
    }

    public static OkHttpClient create(BuildEnvironment environment, AuthInterceptor authInterceptor) {
        OkHttpClient.Builder builder = new OkHttpClient.Builder()
                .connectTimeout(CONNECT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .readTimeout(READ_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .writeTimeout(WRITE_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .retryOnConnectionFailure(true);

        // Add auth interceptor
        if (authInterceptor != null) {
            builder.addInterceptor(authInterceptor);
        }

        // Logging: verbose for dev/staging, minimal for production
        HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor();
        switch (environment) {
            case DEVELOPMENT:
                loggingInterceptor.setLevel(HttpLoggingInterceptor.Level.BODY);
                break;
            case STAGING:
                loggingInterceptor.setLevel(HttpLoggingInterceptor.Level.HEADERS);
                break;
            case PRODUCTION:
                loggingInterceptor.setLevel(HttpLoggingInterceptor.Level.NONE);
                break;
        }
        builder.addInterceptor(loggingInterceptor);

        // Certificate pinning for production only
        if (environment.isPinningEnabled()) {
            builder.certificatePinner(CertificatePinningConfig.createProductionPinner());
        }

        return builder.build();
    }
}

