package com.example.app.network;

import com.google.gson.Gson;
import com.google.gson.GsonBuilder;

import okhttp3.OkHttpClient;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public final class ApiClient {

    private static volatile ApiClient instance;

    private final Retrofit retrofit;
    private final OkHttpClient okHttpClient;
    private final AuthInterceptor authInterceptor;
    private final BuildEnvironment environment;

    private UserApiService userApiService;

    private ApiClient(BuildEnvironment environment) {
        this.environment = environment;
        this.authInterceptor = new AuthInterceptor();
        this.okHttpClient = OkHttpClientFactory.create(environment, authInterceptor);

        Gson gson = new GsonBuilder()
                .setDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'")
                .create();

        this.retrofit = new Retrofit.Builder()
                .baseUrl(environment.getBaseUrl())
                .client(okHttpClient)
                .addConverterFactory(GsonConverterFactory.create(gson))
                .build();
    }

    /**
     * Initialize the ApiClient singleton. Call this once during Application.onCreate().
     */
    public static void initialize(BuildEnvironment environment) {
        if (instance == null) {
            synchronized (ApiClient.class) {
                if (instance == null) {
                    instance = new ApiClient(environment);
                }
            }
        }
    }

    /**
     * Get the singleton instance. Must call initialize() first.
     */
    public static ApiClient getInstance() {
        if (instance == null) {
            throw new IllegalStateException(
                    "ApiClient not initialized. Call ApiClient.initialize(environment) first.");
        }
        return instance;
    }

    /**
     * Reset the singleton (e.g., for environment switching during testing).
     */
    public static synchronized void reset() {
        if (instance != null) {
            instance.okHttpClient.dispatcher().cancelAll();
            instance = null;
        }
    }

    public UserApiService getUserApiService() {
        if (userApiService == null) {
            userApiService = retrofit.create(UserApiService.class);
        }
        return userApiService;
    }

    public AuthInterceptor getAuthInterceptor() {
        return authInterceptor;
    }

    public void setAuthToken(String token) {
        authInterceptor.setAuthToken(token);
    }

    public void clearAuthToken() {
        authInterceptor.clearAuthToken();
    }

    public Retrofit getRetrofit() {
        return retrofit;
    }

    public OkHttpClient getOkHttpClient() {
        return okHttpClient;
    }

    public BuildEnvironment getEnvironment() {
        return environment;
    }
}

