package com.example.app.repository;

import android.util.Log;

import com.example.app.model.User;
import com.example.app.model.UsersResponse;
import com.example.app.network.ApiClient;
import com.example.app.network.NetworkCallback;
import com.example.app.network.UserApiService;

import java.util.List;

import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;

public class UserRepository {

    private static final String TAG = "UserRepository";

    private final UserApiService userApiService;

    public UserRepository() {
        this.userApiService = ApiClient.getInstance().getUserApiService();
    }

    // Constructor for testing with a custom service
    public UserRepository(UserApiService userApiService) {
        this.userApiService = userApiService;
    }

    public void fetchUsers(final NetworkCallback<List<User>> callback) {
        fetchUsers(1, 20, callback);
    }

    public void fetchUsers(int page, int perPage, final NetworkCallback<List<User>> callback) {
        Call<UsersResponse> call = userApiService.getUsers(page, perPage);
        call.enqueue(new Callback<UsersResponse>() {
            @Override
            public void onResponse(Call<UsersResponse> call, Response<UsersResponse> response) {
                if (response.isSuccessful() && response.body() != null) {
                    Log.d(TAG, "Fetched " + response.body().getUsers().size() + " users");
                    callback.onSuccess(response.body().getUsers());
                } else {
                    String errorMsg = "API error: " + response.code();
                    try {
                        if (response.errorBody() != null) {
                            errorMsg = response.errorBody().string();
                        }
                    } catch (Exception e) {
                        Log.e(TAG, "Error reading error body", e);
                    }
                    Log.e(TAG, "fetchUsers failed: " + response.code() + " - " + errorMsg);
                    callback.onError(response.code(), errorMsg);
                }
            }

            @Override
            public void onFailure(Call<UsersResponse> call, Throwable t) {
                Log.e(TAG, "fetchUsers network failure", t);
                callback.onFailure(t);
            }
        });
    }

    public void fetchUser(long userId, final NetworkCallback<User> callback) {
        Call<User> call = userApiService.getUser(userId);
        call.enqueue(new Callback<User>() {
            @Override
            public void onResponse(Call<User> call, Response<User> response) {
                if (response.isSuccessful() && response.body() != null) {
                    callback.onSuccess(response.body());
                } else {
                    String errorMsg = "API error: " + response.code();
                    try {
                        if (response.errorBody() != null) {
                            errorMsg = response.errorBody().string();
                        }
                    } catch (Exception e) {
                        Log.e(TAG, "Error reading error body", e);
                    }
                    callback.onError(response.code(), errorMsg);
                }
            }

            @Override
            public void onFailure(Call<User> call, Throwable t) {
                Log.e(TAG, "fetchUser network failure", t);
                callback.onFailure(t);
            }
        });
    }

    public void createUser(User user, final NetworkCallback<User> callback) {
        Call<User> call = userApiService.createUser(user);
        call.enqueue(new Callback<User>() {
            @Override
            public void onResponse(Call<User> call, Response<User> response) {
                if (response.isSuccessful() && response.body() != null) {
                    callback.onSuccess(response.body());
                } else {
                    String errorMsg = "API error: " + response.code();
                    try {
                        if (response.errorBody() != null) {
                            errorMsg = response.errorBody().string();
                        }
                    } catch (Exception e) {
                        Log.e(TAG, "Error reading error body", e);
                    }
                    callback.onError(response.code(), errorMsg);
                }
            }

            @Override
            public void onFailure(Call<User> call, Throwable t) {
                Log.e(TAG, "createUser network failure", t);
                callback.onFailure(t);
            }
        });
    }
}

