package com.example.app;

import android.app.Application;
import android.util.Log;

import com.example.app.network.ApiClient;
import com.example.app.network.BuildEnvironment;
import com.example.app.network.EnvironmentConfig;

public class MyApplication extends Application {

    private static final String TAG = "MyApplication";

    @Override
    public void onCreate() {
        super.onCreate();

        // Determine environment from BuildConfig or manifest metadata
        BuildEnvironment environment = resolveEnvironment();
        EnvironmentConfig.setEnvironment(environment);

        Log.d(TAG, "Initializing ApiClient for environment: " + environment.name()
                + " baseUrl: " + environment.getBaseUrl()
                + " pinning: " + environment.isPinningEnabled());

        ApiClient.initialize(environment);
    }

    private BuildEnvironment resolveEnvironment() {
        // Use BuildConfig.BUILD_TYPE or a custom BuildConfig field to determine environment.
        // For the MVP, you can set this via build.gradle buildConfigField.
        //
        // Example in build.gradle:
        //   buildTypes {
        //       debug {
        //           buildConfigField "String", "API_ENV", "\"DEVELOPMENT\""
        //       }
        //       staging {
        //           buildConfigField "String", "API_ENV", "\"STAGING\""
        //       }
        //       release {
        //           buildConfigField "String", "API_ENV", "\"PRODUCTION\""
        //       }
        //   }

        try {
            String envName = BuildConfig.BUILD_TYPE;
            if ("debug".equalsIgnoreCase(envName)) {
                return BuildEnvironment.DEVELOPMENT;
            } else if ("staging".equalsIgnoreCase(envName)) {
                return BuildEnvironment.STAGING;
            } else {
                return BuildEnvironment.PRODUCTION;
            }
        } catch (Exception e) {
            Log.w(TAG, "Could not resolve environment, defaulting to PRODUCTION", e);
            return BuildEnvironment.PRODUCTION;
        }
    }
}

