package com.example.app;

import android.os.Bundle;
import android.util.Log;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.example.app.model.User;
import com.example.app.network.ApiClient;
import com.example.app.network.NetworkCallback;
import com.example.app.repository.UserRepository;

import java.util.List;

public class MainActivity extends AppCompatActivity {

    private static final String TAG = "MainActivity";

    private UserRepository userRepository;
    private TextView textViewUsers;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        textViewUsers = findViewById(R.id.textViewUsers);

        // Optionally set auth token if user is logged in
        // ApiClient.getInstance().setAuthToken("user-jwt-token-here");

        userRepository = new UserRepository();
        loadUsers();
    }

    private void loadUsers() {
        userRepository.fetchUsers(new NetworkCallback<List<User>>() {
            @Override
            public void onSuccess(List<User> users) {
                runOnUiThread(() -> {
                    StringBuilder sb = new StringBuilder();
                    sb.append("Loaded ").append(users.size()).append(" users:\n\n");
                    for (User user : users) {
                        sb.append("• ").append(user.getName())
                                .append(" (").append(user.getEmail()).append(")\n");
                    }
                    textViewUsers.setText(sb.toString());
                    Log.d(TAG, "Users loaded successfully");
                });
            }

            @Override
            public void onError(int code, String message) {
                runOnUiThread(() -> {
                    String errorText = "Error " + code + ": " + message;
                    textViewUsers.setText(errorText);
                    Toast.makeText(MainActivity.this, errorText, Toast.LENGTH_LONG).show();
                    Log.e(TAG, errorText);
                });
            }

            @Override
            public void onFailure(Throwable throwable) {
                runOnUiThread(() -> {
                    String failureText = "Network failure: " + throwable.getMessage();
                    textViewUsers.setText(failureText);
                    Toast.makeText(MainActivity.this, failureText, Toast.LENGTH_LONG).show();
                    Log.e(TAG, failureText, throwable);
                });
            }
        });
    }
}

